```csharp
using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;

namespace acmp12
{
    public class Program
    {
        public static void Main()
        {
            StreamReader sr = new StreamReader("D://INPUT.txt");
            StreamWriter sw = new StreamWriter("D://OUTPUT.txt");

            string line = sr.ReadLine();
            var wb = line.Split(' ').Select(int.Parse).ToArray();
            int w = wb[0], b = wb[1];

            Queue<string> que = new Queue<string>();
            bool firstLineOfParagraph = true;
            while (true)
            {
                line = sr.ReadLine();
                if (line == null) break;

                // Check for empty line indicating new paragraph
                if (string.IsNullOrWhiteSpace(line))
                {
                    if (!firstLineOfParagraph)
                    {
                        sw.WriteLine(); // Finish current paragraph
                    }
                    firstLineOfParagraph = true;
                    continue;
                }

                string[] words = line.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
                foreach (string word in words)
                {
                    que.Enqueue(word);
                }

                // Process the words queue and format lines
                while (que.Any())
                {
                    List<string> list = new List<string>();
                    int currentLength = firstLineOfParagraph ? b : 0;
                    string currentWord;

                    // If it's the first line of paragraph, add the indent
                    if (firstLineOfParagraph)
                    {
                        for (int i = 0; i < b; i++)
                        {
                            list.Add(" ");
                        }
                        firstLineOfParagraph = false;
                    }

                    // Add words to the current line until the maximum width is reached
                    while (que.Any() &&
                           ((currentWord = que.Peek()).Length + currentLength + (list.Count > 1 ? 1 : 0) <= w))
                    {
                        que.Dequeue();
                        list.Add(currentWord);
                        currentLength += currentWord.Length + (list.Count > 1 ? 1 : 0); // plus a space if not the first word
                    }

                    // Write the line to the file
                    sw.WriteLine(string.Join(" ", list).TrimEnd());
                }
            }

            sr.Close();
            sw.Close();
        }
    }
}
