                if (!newParagraph)
                {
                    formattedText.AppendLine(); // Добавляем пустую строку между абзацами
                    newParagraph = true; // Сначала следующего абзаца добавим отступ
                }
            }
            else
            {
                // Если это новый абзац, добавим отступ только к первой строке
                if (newParagraph)
                {
                    formattedText.Append(' ', b); // Добавляем отступ
                    newParagraph = false; // Сбрасываем флаг, так что отступ больше не будет добавлен
                }

                string[] words = line.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
