                    if (formattedText.Length - formattedText.ToString().LastIndexOf('\n') - 1 + 
                        wordWithPunctuation.Length + (formattedText.Length > b ? 1 : 0) <= w)
                    {
                        if (formattedText.Length > b && !formattedText.ToString().EndsWith("\n")) 
                            formattedText.Append(' '); // Add a space if it's not the first word on the line
                        formattedText.Append(wordWithPunctuation);
                    }
                    else
                    {
                        // Start a new line if the word doesn't fit
                        formattedText.AppendLine();
                        if (newParagraph)
                        {
                            formattedText.Append(' ', b); // Add indent for a new paragraph
                            newParagraph = false; // And reset the flag
                        }
                        formattedText.Append(wordWithPunctuation);
