using System;
using System.IO;
using System.Text;

class Program
{
    static void Main(string[] args)
    {
        string inputFile = "INPUT.TXT";
        string outputFile = "OUTPUT.TXT";
        string[] lines = File.ReadAllLines(inputFile);
        string[] parameters = lines[0].Split(' ');
        int w = int.Parse(parameters[0]);
        int b = int.Parse(parameters[1]);

        StringBuilder formattedText = new StringBuilder();
        bool indentNeeded = true;

        foreach (string line in lines.Skip(1))
        {
            string trimmedLine = line.Trim();
            if (trimmedLine == string.Empty) // Новый абзац
            {
                if (!indentNeeded)
                {
                    formattedText.AppendLine();
                    indentNeeded = true; // Для следующего абзаца отступ нужен
                }
            }
            else
            {
                string[] words = trimmedLine.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
                foreach (string word in words)
                {
                    // Обработка знаков препинания и определение, нужен ли пробел после них
                    string processedWord = ProcessPunctuation(word);

                    // Если текущая строка + новое слово превышают максимальную ширину
                    if (NeedsNewLine(formattedText.ToString(), processedWord, w, b))
                    {
                        formattedText.AppendLine(); // Переходим на новую строку
                        indentNeeded = false; // Отступ не нужен, если уже в середине абзаца
                    }

                    // Если строка пустая (новая строка либо начало текста), и требуется отступ
                    if (indentNeeded && (formattedText.Length == 0 || formattedText.ToString().EndsWith("\n")))
                    {
                        formattedText.Append(' ', b); // Добавляем отступ
                        indentNeeded = false;
                    }

                    // Добавляем слово и пробел, если это не начало строки
                    if (formattedText.Length > 0 && !formattedText.ToString().EndsWith("\n"))
                        formattedText.Append(' ');

                    formattedText.Append(processedWord);
                }
            }
        }

        // Write to output file
        File.WriteAllText(outputFile, formattedText.ToString().TrimEnd());
    }

    // Определяет, нужно ли добавить новую строку
    private static bool NeedsNewLine(string currentText, string word, int maxWidth, int indentWidth)
    {
        int currentLineLength = currentText.Length - currentText.LastIndexOf('\n') - 1;
        // Прибавляем 1 для потенциального пробела перед словом
        int wordLength = word.Length + (currentText.Length > 0 && !currentText.EndsWith("\n") ? 1 : 0);
        return currentLineLength + wordLength > maxWidth;
    }

    // Обрабатывает знаки препинания в словах
    private static string ProcessPunctuation(string word)
    {
        // Определяем знаки препинания, после которых нужен пробел
        char[] punctuationWithSpace = new[] { ',', ';', ':', '!', '?' };
        if (word.Length > 1 && punctuationWithSpace.Contains(word[word.Length - 1]))
        {
            // Добавляем пробел после знака препинания
            return word + " ";
        }
        return word;
    }
}
